// Chestnut site engine: renders the pet from the app's own frame data
// (sprites.js, generated by `make site`) and drives interactive re-creations
// of the Vault Hopper, Quick Capture, and Note Courier flows. Vanilla JS,
// no build step.
"use strict";

const S = window.CHESTNUT_SPRITES;

// ---------------------------------------------------------------------------
// Sprite textures: each frame pre-rendered 1:1 on an offscreen canvas, then
// drawn upscaled with smoothing off — same nearest-neighbor look as the app.
// ---------------------------------------------------------------------------

const textureCache = new Map(); // themeId -> {frameName -> canvas}

function texturesFor(theme) {
  let frames = textureCache.get(theme.id);
  if (frames) return frames;
  frames = {};
  const all = Object.assign({ zPixel: S.zPixel }, S.frames);
  for (const [name, rows] of Object.entries(all)) {
    const c = document.createElement("canvas");
    c.width = rows[0].length;
    c.height = rows.length;
    const ctx = c.getContext("2d");
    rows.forEach((row, y) => {
      [...row].forEach((ch, x) => {
        const hex = theme.palette[ch];
        if (!hex || hex.endsWith("00")) return;
        ctx.fillStyle = "#" + hex.slice(1, 7);
        ctx.globalAlpha = parseInt(hex.slice(7, 9), 16) / 255;
        ctx.fillRect(x, y, 1, 1);
      });
    });
    frames[name] = c;
  }
  textureCache.set(theme.id, frames);
  return frames;
}

// Opaque mask from the base frame (identical silhouette across all states,
// same guarantee the app relies on for hit-testing).
const opaqueMask = S.frames.base.map((row) => [...row].map((ch) => ch !== "."));

// ---------------------------------------------------------------------------
// Pet state machine — mirrors PetScene's states and timings.
// ---------------------------------------------------------------------------

const canvas = document.getElementById("pet");
const dpr = window.devicePixelRatio || 1;
const ctx = canvas.getContext("2d");
const BASELINE = 4; // transparent strip under the sprite
let SCALE, CANVAS_W, CANVAS_H;

// Css px per sprite pixel. Mutable so the menu's Size submenu can resize the
// pet; resizing the canvas resets the context, so transform and smoothing are
// re-applied here.
function setScale(s) {
  SCALE = s;
  CANVAS_W = (S.gridWidth + 2) * SCALE;
  CANVAS_H = 27 * SCALE; // sprite + headroom for hop and drifting z's
  canvas.style.width = CANVAS_W + "px";
  canvas.style.height = CANVAS_H + "px";
  canvas.width = CANVAS_W * dpr;
  canvas.height = CANVAS_H * dpr;
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  ctx.imageSmoothingEnabled = false;
  // Panels, notice bubble, and chip-opened menu hug the sprite's top edge,
  // whatever size the menu has picked.
  canvas.parentElement.style.setProperty(
    "--panel-bottom", BASELINE + S.gridHeight * SCALE + 14 + "px"
  );
}
setScale(8); // "Medium" in the size menu

const rand = (lo, hi) => lo + Math.random() * (hi - lo);
const easeOut = (x) => 1 - (1 - x) * (1 - x);
const easeIn = (x) => x * x;

// Site mode: html[data-theme] (set by the toggle, persisted) wins over the
// OS scheme. The sprite's default theme follows the mode until the visitor
// picks one by hand.
const mediaLight = window.matchMedia("(prefers-color-scheme: light)");

function effectiveMode() {
  const m = document.documentElement.dataset.theme;
  return m === "light" || m === "dark" ? m : mediaLight.matches ? "light" : "dark";
}

function defaultThemeFor(mode) {
  const id = mode === "light" ? "sunbleached" : "obsidian-night";
  return S.themes.find((t) => t.id === id) || S.themes[0];
}

let theme = defaultThemeFor(effectiveMode());

const pet = {
  state: "idle",          // idle | writing | sleep
  hover: false,
  openWide: false,        // held pose while the hopper palette is up
  burst: null,            // {start, cycles} chatter animation
  gesture: null,          // {type: "hop"|"gulp", start}
  nextPeek: performance.now() / 1000 + rand(8, 20), // idle: next eye peek
  peekStart: null,
  nextChatter: null,      // writing: next single chatter cycle
  writingUntil: 0,
  zs: [],                 // sleep: drifting z pixels
  nextZ: 0,
  lastActivity: 0,
  napUntil: 0,            // menu's Quit gag: activity can't wake it until then
};

const BREATHE = {
  idle: { period: 2.6, amount: 1.03 },
  writing: { period: 2.0, amount: 1.02 },
  sleep: { period: 4.5, amount: 1.02 },
  hover: { period: 2.0, amount: 1.02 },
};

// Chatter burst: [base, open, glint, open] per cycle, 0.2s per frame,
// settling on glint — PetScene.chatterBurst verbatim.
const CHATTER_FRAMES = ["base", "chatterOpen", "glint", "chatterOpen"];
const CHATTER_DT = 0.2;

function burstTexture(t) {
  const elapsed = t - pet.burst.start;
  const total = pet.burst.cycles * CHATTER_FRAMES.length * CHATTER_DT;
  if (elapsed >= total) {
    pet.burst = null;
    if (pet.state === "writing") pet.nextChatter = t + rand(5, 25);
    return null;
  }
  return CHATTER_FRAMES[Math.floor(elapsed / CHATTER_DT) % CHATTER_FRAMES.length];
}

// Gestures return {tex, dy, sx, sy} while running, null when done.
function gestureFrame(t) {
  const g = pet.gesture;
  const e = t - g.start;
  if (g.type === "hop") {
    // Up 0.18 easeOut / down 0.18 easeIn with squash-and-stretch, then a
    // quick 0.08 settle — PetScene.handleClick.
    if (e < 0.18) {
      const p = easeOut(e / 0.18);
      return { tex: null, dy: 5 * p, sx: 1 - 0.08 * p, sy: 1 + 0.08 * p };
    }
    if (e < 0.36) {
      const p = easeIn((e - 0.18) / 0.18);
      return { tex: null, dy: 5 * (1 - p), sx: 0.92 + 0.16 * p, sy: 1.08 - 0.16 * p };
    }
    if (e < 0.44) {
      const p = (e - 0.36) / 0.08;
      return { tex: null, dy: 0, sx: 1.08 - 0.08 * p, sy: 0.92 + 0.08 * p };
    }
    return null;
  }
  // Gulp: open 0.15, squash 0.1, release 0.12, satisfied glint 0.4 —
  // PetScene.celebrateDelivery.
  if (e < 0.15) return { tex: "chatterOpen", dy: 0, sx: 1, sy: 1 };
  if (e < 0.25) return { tex: "base", dy: 0, sx: 1, sy: 1 - 0.1 * easeIn((e - 0.15) / 0.1) };
  if (e < 0.37) return { tex: "base", dy: 0, sx: 1, sy: 0.9 + 0.1 * easeOut((e - 0.25) / 0.12) };
  if (e < 0.77) return { tex: "glint", dy: 0, sx: 1, sy: 1 };
  return null;
}

// Idle eye peek: left 0.5, right 0.5, left 0.35 — PetScene.scheduleEyePeek.
function eyePeekTexture(t) {
  const e = t - pet.peekStart;
  if (e < 0.5) return "eyePeekLeft";
  if (e < 1.0) return "eyePeekRight";
  if (e < 1.35) return "eyePeekLeft";
  pet.peekStart = null;
  pet.nextPeek = t + rand(8, 20);
  return null;
}

function baseTexture() {
  if (pet.openWide) return "chatterOpen";
  if (pet.hover) return "peek";
  if (pet.state === "sleep") return "asleep";
  if (pet.state === "writing") return "glint";
  return "base";
}

function update(t) {
  // Sleep after 90s without page interaction (any activity wakes it).
  if (pet.state !== "sleep" && !pet.openWide && !capturePanelOpen() &&
      t - pet.lastActivity > 90 && pet.state === "idle") {
    pet.state = "sleep";
    pet.nextZ = t + 0.5;
    pet.zs = [];
  }
  if (pet.state === "writing" && t > pet.writingUntil) {
    pet.state = "idle";
    pet.burst = null;
    pet.nextPeek = t + rand(8, 20);
  }

  let tex = null, dy = 0, sx = 1, sy = 1, breathing = true;

  if (pet.gesture) {
    const g = gestureFrame(t);
    if (g) {
      tex = g.tex || baseTexture();
      ({ dy, sx, sy } = g);
      breathing = false;
    } else {
      pet.gesture = null;
    }
  }

  if (!pet.gesture && pet.burst && !pet.openWide && !pet.hover) {
    const b = burstTexture(t);
    if (b) { tex = b; }
  }

  if (!tex) {
    // Writing: occasional single chatter cycle every 5–25s.
    if (pet.state === "writing" && !pet.burst && pet.nextChatter && t > pet.nextChatter &&
        !pet.openWide && !pet.hover && !pet.gesture) {
      pet.burst = { start: t, cycles: 1 };
      pet.nextChatter = null;
      tex = burstTexture(t);
    }
    // Idle: eye peeks.
    if (!tex && pet.state === "idle" && !pet.openWide && !pet.hover && !pet.gesture) {
      if (pet.peekStart != null) tex = eyePeekTexture(t);
      else if (t > pet.nextPeek) { pet.peekStart = t; tex = "eyePeekLeft"; }
    }
    if (!tex) tex = baseTexture();
  }

  if (breathing && !pet.openWide) {
    const b = pet.hover ? BREATHE.hover : BREATHE[pet.state];
    sy *= 1 + ((b.amount - 1) / 2) * (1 - Math.cos((2 * Math.PI * t) / b.period));
  }

  // Sleep z's: spawn every 1.6s, drift up-right over 2.2s and fade.
  if (pet.state === "sleep") {
    if (t > pet.nextZ) {
      pet.zs.push({ start: t });
      pet.nextZ = t + 1.6;
    }
  }
  pet.zs = pet.zs.filter((z) => t - z.start < 2.2);

  draw(tex, dy, sx, sy, t);
}

function draw(texName, dy, sx, sy, t) {
  ctx.clearRect(0, 0, CANVAS_W, CANVAS_H);
  const frames = texturesFor(theme);
  const tex = frames[texName];
  const w = S.gridWidth * SCALE * sx;
  const h = S.gridHeight * SCALE * sy;
  const cx = CANVAS_W / 2;
  const baseY = CANVAS_H - BASELINE - dy * SCALE;
  ctx.drawImage(tex, cx - w / 2, baseY - h, w, h);

  const zTex = frames.zPixel;
  for (const z of pet.zs) {
    const p = (t - z.start) / 2.2;
    const zScale = SCALE / 2;
    ctx.globalAlpha = 1 - p;
    ctx.drawImage(
      zTex,
      cx + S.gridWidth * SCALE * 0.25 + p * 2 * SCALE,
      baseY - S.gridHeight * SCALE * 0.9 - p * 6 * SCALE - zTex.height * zScale,
      zTex.width * zScale, zTex.height * zScale
    );
    ctx.globalAlpha = 1;
  }
}

function frameLoop(nowMs) {
  update(nowMs / 1000);
  requestAnimationFrame(frameLoop);
}
requestAnimationFrame(frameLoop);

// ---------------------------------------------------------------------------
// Pet interaction: per-pixel hover (base silhouette), click hop, wake.
// ---------------------------------------------------------------------------

function spriteHit(ev) {
  const rect = canvas.getBoundingClientRect();
  const x = ev.clientX - rect.left;
  const y = ev.clientY - rect.top;
  const col = Math.floor((x - (CANVAS_W - S.gridWidth * SCALE) / 2) / SCALE);
  const row = Math.floor((y - (CANVAS_H - BASELINE - S.gridHeight * SCALE)) / SCALE);
  return (
    row >= 0 && row < S.gridHeight && col >= 0 && col < S.gridWidth &&
    opaqueMask[row][col]
  );
}

canvas.addEventListener("pointermove", (ev) => {
  pet.hover = spriteHit(ev);
  canvas.style.cursor = pet.hover ? "pointer" : "default";
});
canvas.addEventListener("pointerleave", () => { pet.hover = false; });
canvas.addEventListener("click", (ev) => {
  if (spriteHit(ev) && !pet.gesture) {
    pet.gesture = { type: "hop", start: performance.now() / 1000 };
  }
});

function noteActivity() {
  const t = performance.now() / 1000;
  if (pet.state === "sleep" && t < pet.napUntil) return;
  pet.lastActivity = t;
  if (pet.state === "sleep") {
    pet.state = "idle";
    pet.zs = [];
    pet.nextPeek = t + rand(8, 20);
  }
}
window.addEventListener("pointermove", noteActivity, { passive: true });
window.addEventListener("keydown", noteActivity, { passive: true });
window.addEventListener("scroll", noteActivity, { passive: true });
noteActivity();

// ---------------------------------------------------------------------------
// Sprite theme — picked in the menu re-creation's Theme submenu (like the
// app); follows the site mode until the visitor chooses one there.
// ---------------------------------------------------------------------------

let userPickedTheme = false;

function setSpriteTheme(t) {
  theme = t;
}

// ---------------------------------------------------------------------------
// Demo vaults, shared by both panels.
// ---------------------------------------------------------------------------

const vaults = [
  { name: "Work", path: "~/Vaults/Work", open: true },
  { name: "Personal", path: "~/Vaults/Personal", open: true },
  { name: "Research", path: "~/Notes/Research", open: false },
];
let pinnedPath = "~/Vaults/Work";

const PIN_SVG = '<svg viewBox="0 0 16 16" fill="currentColor"><path d="M9.5 1.5 14.5 6.5 13 8l-.7-.2-2.6 2.6.3 2.6-1.2 1.2L5.6 11 2.5 14.1l-1-1L4.6 10 1.4 6.8l1.2-1.2 2.6.3L7.8 3.3 7.6 2.6z"/></svg>';
const PIN_SLASH_SVG = '<svg viewBox="0 0 16 16" fill="currentColor"><path d="M9.5 1.5 14.5 6.5 13 8l-.7-.2-1.5 1.5-1.4-1.4 1.5-1.5-1.7-1.7-1.5 1.5L6.3 4.8l1.5-1.5-.2-.7zM2 2l12 12-.9.9L1.1 2.9zm3.3 6.2 2.1 2.1-1.8.7-3.1 3.1-1-1L4.6 10z"/></svg>';

// ---------------------------------------------------------------------------
// Panel management (exclusive, like the app's panel swap).
// ---------------------------------------------------------------------------

const hopperEl = document.getElementById("hopper");
const captureEl = document.getElementById("capture");
const chipHopper = document.getElementById("chip-hopper");
const chipCapture = document.getElementById("chip-capture");

const capturePanelOpen = () => !captureEl.hidden;

function syncChips() {
  chipHopper.classList.toggle("active", !hopperEl.hidden);
  chipCapture.classList.toggle("active", !captureEl.hidden);
  chipMenu.classList.toggle("active", !menuEl.hidden);
}

function closePanels() {
  hopperEl.hidden = true;
  captureEl.hidden = true;
  menuEl.hidden = true;
  pet.openWide = false;
  courierDrop = null; // a dismissed destination picker abandons the delivery
  syncChips();
}

function toggleHopper() {
  const wasOpen = !hopperEl.hidden;
  closePanels();
  if (!wasOpen) openHopper();
}

function toggleCapture() {
  const wasOpen = !captureEl.hidden;
  closePanels();
  if (!wasOpen) openCapture();
}

chipHopper.addEventListener("click", toggleHopper);
chipCapture.addEventListener("click", toggleCapture);

// The app's default global hotkeys, as an easter egg.
window.addEventListener("keydown", (ev) => {
  if (ev.ctrlKey && ev.altKey && ev.code === "KeyV") { ev.preventDefault(); toggleHopper(); }
  if (ev.ctrlKey && ev.altKey && ev.code === "Space") { ev.preventDefault(); toggleCapture(); }
  if (ev.ctrlKey && ev.altKey && ev.code === "KeyC") {
    ev.preventDefault();
    closePanels();
    showNotice("Paste → plugin", "Sent clipboard to a matching plugin",
      "Demo only, no real plugin ran");
  }
  if (ev.ctrlKey && ev.altKey && ev.code === "KeyO") {
    ev.preventDefault();
    if (!noticeEl.hidden) {
      clearTimeout(noticeTimer);
      noticeEl.hidden = true;
      if (!pet.gesture) pet.gesture = { type: "hop", start: performance.now() / 1000 };
    }
  }
  if (ev.key === "Escape") closePanels();
});

// ---------------------------------------------------------------------------
// Vault palette: the Vault Hopper, doubling as the courier destination
// picker — one element configured per mode, like the app's VaultPalettePanel.
// ---------------------------------------------------------------------------

const hopperFilter = document.getElementById("hopper-filter");
const hopperList = document.getElementById("hopper-list");
const paletteHints = document.getElementById("palette-hints");
const HOPPER_PLACEHOLDER = hopperFilter.placeholder; // HTML is the source of truth
const HOPPER_HINTS = paletteHints.innerHTML;
const NB3 = "\u00a0\u00a0\u00a0"; // hint-item gap, same as the HTML hints' \&nbsp;s
let paletteMode = "hopper"; // "hopper" | "courier"
let courierDrop = null;     // {label, sourcePath} while a delivery is in flight
let hopperOrder = [];  // pin-first order, fixed while the palette is open
let hopperSelection = 0;

function hopperFiltered() {
  const q = hopperFilter.value.trim().toLowerCase();
  return q ? hopperOrder.filter((v) => v.name.toLowerCase().includes(q)) : hopperOrder;
}

function openHopper() { openPalette("hopper", null); }

// Courier mode mirrors AppDelegate.beginDelivery: destinations exclude the
// source vault, the placeholder tracks copy-vs-move, no daily-note shortcut.
function openPalette(mode, drop) {
  paletteMode = mode;
  courierDrop = drop;
  const pool = vaults.filter((v) => !drop || v.path !== drop.sourcePath);
  hopperOrder = [...pool].sort(
    (a, b) => (b.path === pinnedPath) - (a.path === pinnedPath)
  );
  if (mode === "courier") {
    hopperFilter.placeholder = menuState.copyOnDrop ? "Copy to vault…" : "Deliver to vault…";
    paletteHints.textContent = `⏎ open${NB3}⌥⏎ reveal in Finder${NB3}⌘P pin`;
  } else {
    hopperFilter.placeholder = HOPPER_PLACEHOLDER;
    paletteHints.innerHTML = HOPPER_HINTS;
  }
  hopperFilter.value = "";
  hopperSelection = 0;
  hopperEl.hidden = false;
  pet.openWide = true;
  syncChips();
  renderHopper();
  hopperFilter.focus();
}

function renderHopper() {
  const filtered = hopperFiltered();
  hopperList.innerHTML = "";
  if (filtered.length === 0) {
    const empty = document.createElement("div");
    empty.className = "no-match";
    empty.textContent = "No matching vault";
    hopperList.appendChild(empty);
    return;
  }
  filtered.forEach((v, i) => {
    const row = document.createElement("div");
    row.className = "vault-row" + (i === hopperSelection ? " selected" : "");
    const pinned = v.path === pinnedPath;
    row.innerHTML =
      `<span class="names"><span class="vault-name"></span>` +
      `<span class="vault-path"></span></span>` +
      `<button class="pin-btn${pinned ? " pinned" : ""}" ` +
      `title="${pinned ? "Unpin" : "Pin as home vault"}">${PIN_SVG}</button>`;
    row.querySelector(".vault-name").textContent = v.name;
    row.querySelector(".vault-path").textContent = v.path;
    const pinBtn = row.querySelector(".pin-btn");
    if (pinned) {
      pinBtn.addEventListener("pointerenter", () => { pinBtn.innerHTML = PIN_SLASH_SVG; });
      pinBtn.addEventListener("pointerleave", () => { pinBtn.innerHTML = PIN_SVG; });
    }
    pinBtn.addEventListener("click", (ev) => {
      ev.stopPropagation();
      togglePin(v);
    });
    row.addEventListener("pointerenter", () => {
      if (hopperSelection !== i) {
        hopperSelection = i;
        renderHopper();
      }
    });
    row.addEventListener("click", () => hopperCommit());
    hopperList.appendChild(row);
  });
}

// Pin-first order applies on next open, never re-sorts the open palette —
// same behavior as the app.
function togglePin(v) {
  pinnedPath = v.path === pinnedPath ? null : v.path;
  renderHopper();
}

function hopperCommit() {
  const target = hopperFiltered()[hopperSelection];
  const drop = courierDrop;
  const mode = paletteMode;
  closePanels();
  if (mode === "courier" && target && drop) {
    completeDelivery(target, drop);
  } else if (!pet.gesture) {
    pet.gesture = { type: "hop", start: performance.now() / 1000 };
  }
}

hopperFilter.addEventListener("input", () => {
  hopperSelection = 0;
  renderHopper();
});
hopperFilter.addEventListener("keydown", (ev) => {
  const filtered = hopperFiltered();
  if (ev.key === "ArrowDown" || ev.key === "ArrowUp") {
    ev.preventDefault();
    const delta = ev.key === "ArrowDown" ? 1 : -1;
    hopperSelection = Math.min(Math.max(hopperSelection + delta, 0), filtered.length - 1);
    renderHopper();
  } else if (ev.key === "Enter") {
    ev.preventDefault();
    if (filtered.length > 0) hopperCommit();
  } else if ((ev.metaKey || ev.ctrlKey) && ev.key.toLowerCase() === "p") {
    ev.preventDefault();
    if (filtered[hopperSelection]) togglePin(filtered[hopperSelection]);
  }
});

// ---------------------------------------------------------------------------
// Note Courier demo: drag the demo note — or a real file from the Finder —
// onto Chestnut, pick a destination, gulp. Real files contribute their
// name only; contents are never read.
// ---------------------------------------------------------------------------

const noteTile = document.getElementById("demo-note");
const DEMO_NOTE = { label: "Meeting notes.md", sourcePath: "~/Vaults/Work" };

function beginDelivery(drop) {
  closePanels();
  openPalette("courier", drop);
}

// Mirrors AppDelegate.completeDelivery: gulp + "Copied/Delivered to" receipt.
function completeDelivery(vault, drop) {
  pet.state = "idle";
  pet.gesture = { type: "gulp", start: performance.now() / 1000 };
  showNotice(
    `${menuState.copyOnDrop ? "Copied" : "Delivered"} to ${vault.name}`,
    drop.label,
    "Demo only, nothing was moved"
  );
}

// Pointer-based drag (not HTML5 drag-and-drop) so it works on touch too.
// A plain click or tap skips the theatrics and opens the picker directly.
let noteDrag = null; // {startX, startY, active, ghost}

function makeGhost() {
  const ghost = noteTile.cloneNode(true);
  ghost.classList.add("drag-ghost");
  // cloneNode doesn't copy a canvas's bitmap — repaint the pixel icon.
  ghost.querySelector("canvas").getContext("2d")
    .drawImage(noteTile.querySelector("canvas"), 0, 0);
  document.body.appendChild(ghost);
  return ghost;
}

noteTile.addEventListener("pointerdown", (ev) => {
  if (ev.button !== 0) return;
  ev.preventDefault();
  noteTile.setPointerCapture(ev.pointerId);
  noteDrag = { startX: ev.clientX, startY: ev.clientY, active: false, ghost: null };
});

noteTile.addEventListener("pointermove", (ev) => {
  if (!noteDrag) return;
  if (!noteDrag.active) {
    if (Math.hypot(ev.clientX - noteDrag.startX, ev.clientY - noteDrag.startY) < 5) return;
    noteDrag.active = true;
    closePanels();
    noteDrag.ghost = makeGhost();
    noteTile.classList.add("dragging");
  }
  noteDrag.ghost.style.left = ev.clientX + "px";
  noteDrag.ghost.style.top = ev.clientY + "px";
  const over = spriteHit(ev);
  pet.openWide = over; // mouth opens as the note hovers over it
  // "+" cursor over the pet when the drop would copy, like a macOS drag.
  // Set on both the capture target and the root: with pointer capture,
  // browsers disagree on which element's cursor wins.
  const cursor = over ? (menuState.copyOnDrop ? "copy" : "default") : "grabbing";
  noteTile.style.cursor = cursor;
  document.documentElement.style.cursor = cursor;
});

function endNoteDrag() {
  noteDrag.ghost.remove();
  noteTile.classList.remove("dragging");
  noteTile.style.cursor = "";
  document.documentElement.style.cursor = "";
}

noteTile.addEventListener("pointerup", (ev) => {
  if (!noteDrag) return;
  const wasDrag = noteDrag.active;
  if (wasDrag) endNoteDrag();
  noteDrag = null;
  if (!wasDrag || spriteHit(ev)) beginDelivery(DEMO_NOTE);
  else pet.openWide = false;
});

noteTile.addEventListener("pointercancel", () => {
  if (noteDrag && noteDrag.active) {
    endNoteDrag();
    pet.openWide = false;
  }
  noteDrag = null;
});

noteTile.addEventListener("keydown", (ev) => {
  if (ev.key === "Enter" || ev.key === " ") {
    ev.preventDefault();
    beginDelivery(DEMO_NOTE);
  }
});

// Real files from the Finder: same flow, sourced from outside any vault so
// every demo vault is offered (matches beginDelivery's nil source).
const panelIsOpen = () => !hopperEl.hidden || !captureEl.hidden;

canvas.addEventListener("dragover", (ev) => {
  ev.preventDefault();
  const over = spriteHit(ev);
  if (over) pet.openWide = true;
  else if (!panelIsOpen()) pet.openWide = false;
  ev.dataTransfer.dropEffect = over ? (menuState.copyOnDrop ? "copy" : "move") : "none";
});

canvas.addEventListener("dragleave", () => {
  if (!panelIsOpen()) pet.openWide = false;
});

canvas.addEventListener("drop", (ev) => {
  ev.preventDefault();
  if (!spriteHit(ev)) return;
  const files = ev.dataTransfer.files;
  const label =
    files.length > 1 ? `${files.length} files` : files[0] ? files[0].name : "1 item";
  beginDelivery({ label, sourcePath: null });
});

// A drop that misses Chestnut shouldn't navigate the page to the file.
window.addEventListener("dragover", (ev) => ev.preventDefault());
window.addEventListener("drop", (ev) => ev.preventDefault());

// ---------------------------------------------------------------------------
// Quick Capture demo.
// ---------------------------------------------------------------------------

const editor = document.getElementById("capture-editor");
const targetSelect = document.getElementById("capture-target");
const targetDot = document.getElementById("capture-dot");
const submitBtn = document.getElementById("capture-submit");
const toolbar = document.getElementById("capture-toolbar");

for (const v of vaults) {
  const opt = document.createElement("option");
  opt.value = v.path;
  opt.textContent = v.name;
  targetSelect.appendChild(opt);
}
targetSelect.addEventListener("change", syncCaptureFooter);

function syncCaptureFooter() {
  const v = vaults.find((x) => x.path === targetSelect.value);
  targetDot.classList.toggle("closed", !(v && v.open));
  submitBtn.disabled = editor.value.trim() === "";
}

function openCapture() {
  captureEl.hidden = false;
  pet.openWide = true; // mouth open awaiting the capture, like the hopper
  syncChips();
  syncCaptureFooter();
  editor.focus();
}

// Typing drives the pet's writing state: two chatter cycles greet the
// session, then the attentive glint with an occasional single cycle.
editor.addEventListener("input", () => {
  const t = performance.now() / 1000;
  pet.openWide = false; // typing hands the pose over to the writing state
  if (pet.state !== "writing") {
    pet.state = "writing";
    pet.burst = { start: t, cycles: 2 };
    pet.nextChatter = null;
  }
  pet.writingUntil = t + 8;
  syncCaptureFooter();
});

// Markdown toolbar — same actions as the app's.
const MD_ACTIONS = [
  { label: "B", cls: "tb-bold", tip: "Bold (⌘B)", wrap: ["**", "**", "bold"] },
  { label: "I", cls: "tb-italic", tip: "Italic (⌘I)", wrap: ["_", "_", "italic"] },
  { label: "S", cls: "tb-strike", tip: "Strikethrough", wrap: ["~~", "~~", "strikethrough"] },
  { label: "</>", cls: "", tip: "Inline code", wrap: ["`", "`", "code"] },
  { label: "{}", cls: "", tip: "Code block", wrap: ["```\n", "\n```", "code"] },
  { label: "H", cls: "", tip: "Heading", line: "## " },
  { label: "☐", cls: "", tip: "Task", line: "- [ ] " },
  { label: "🔗", cls: "", tip: "Link (⌘K)", link: true },
];

function applyMarkdown(action) {
  const start = editor.selectionStart;
  const end = editor.selectionEnd;
  const selected = editor.value.slice(start, end);
  let insert, selStart, selEnd;

  if (action.line) {
    const lineStart = editor.value.lastIndexOf("\n", start - 1) + 1;
    editor.value = editor.value.slice(0, lineStart) + action.line + editor.value.slice(lineStart);
    selStart = start + action.line.length;
    selEnd = end + action.line.length;
  } else if (action.link) {
    const text = selected || "title";
    insert = `[${text}](url)`;
    editor.value = editor.value.slice(0, start) + insert + editor.value.slice(end);
    selStart = start + text.length + 3;
    selEnd = selStart + 3;
  } else {
    const [pre, suf, ph] = action.wrap;
    const text = selected || ph;
    insert = pre + text + suf;
    editor.value = editor.value.slice(0, start) + insert + editor.value.slice(end);
    selStart = start + pre.length;
    selEnd = selStart + text.length;
  }
  editor.focus();
  editor.setSelectionRange(selStart, selEnd);
  syncCaptureFooter();
}

for (const action of MD_ACTIONS) {
  const btn = document.createElement("button");
  btn.textContent = action.label;
  if (action.cls) btn.className = action.cls;
  btn.title = action.tip;
  btn.addEventListener("click", () => applyMarkdown(action));
  toolbar.appendChild(btn);
}

editor.addEventListener("keydown", (ev) => {
  if ((ev.metaKey || ev.ctrlKey) && ev.key === "Enter") {
    ev.preventDefault();
    submitCapture();
  } else if ((ev.metaKey || ev.ctrlKey) && ev.key.toLowerCase() === "b") {
    ev.preventDefault();
    applyMarkdown(MD_ACTIONS[0]);
  } else if ((ev.metaKey || ev.ctrlKey) && ev.key.toLowerCase() === "i") {
    ev.preventDefault();
    applyMarkdown(MD_ACTIONS[1]);
  } else if ((ev.metaKey || ev.ctrlKey) && ev.key.toLowerCase() === "k") {
    ev.preventDefault();
    applyMarkdown(MD_ACTIONS[7]);
  }
});

submitBtn.addEventListener("click", submitCapture);

function submitCapture() {
  if (editor.value.trim() === "") return;
  const vault = vaults.find((x) => x.path === targetSelect.value) || vaults[0];
  editor.value = ""; // successful capture clears the draft, like the app
  closePanels();
  pet.state = "idle";
  pet.gesture = { type: "gulp", start: performance.now() / 1000 };
  const today = new Date().toISOString().slice(0, 10);
  showNotice(`Captured to ${vault.name} › ${today}.md`, "Appended to today's note");
}

// ---------------------------------------------------------------------------
// Notice bubble.
// ---------------------------------------------------------------------------

const noticeEl = document.getElementById("notice");
let noticeTimer = null;

function showNotice(title, subtitle, hint) {
  document.getElementById("notice-title").textContent = title;
  document.getElementById("notice-subtitle").textContent = subtitle;
  document.querySelector(".notice-hint").textContent =
    hint || "Demo only, nothing was written";
  noticeEl.hidden = false;
  noticeEl.style.opacity = "1";
  clearTimeout(noticeTimer);
  noticeTimer = setTimeout(() => {
    noticeEl.style.opacity = "0";
    noticeTimer = setTimeout(() => { noticeEl.hidden = true; }, 320);
  }, 5000);
}

noticeEl.addEventListener("click", () => {
  clearTimeout(noticeTimer);
  noticeEl.hidden = true;
});

// ---------------------------------------------------------------------------
// Right-click menu — re-creation of the app's context menu (PetWindow.showMenu).
// Size/Theme/Opacity really restyle the canvas pet, Vaults…/Capture… open the
// demo panels, and the ↗ rows are real browser links, just like the app's.
// ---------------------------------------------------------------------------

const stageEl = document.getElementById("stage");
const menuEl = document.getElementById("menu");
const chipMenu = document.getElementById("chip-menu");

const SIZE_SCALES = { Small: 5, Medium: 8, Large: 11 };
const menuState = {
  size: "Medium",
  opacity: 1,
  copyOnDrop: true,
  showInFullScreen: true,
  launchAtLogin: true,
  plugins: {},
};

// Outline heart, like the app's SF Symbol on Support Chestnut.
const HEART_SVG =
  '<svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="1.4">' +
  '<path d="M8 13.5C4.8 11 1.8 8.6 1.8 5.7 1.8 4 3.2 2.6 4.9 2.6c1.2 0 2.4.7 3.1 1.8' +
  '.7-1.1 1.9-1.8 3.1-1.8 1.7 0 3.1 1.4 3.1 3.1 0 2.9-3 5.3-6.2 7.8z"/></svg>';

function menuItem({ label, check, hint, badge, icon, disabled, submenu, action }) {
  const item = document.createElement("div");
  item.className = "menu-item" + (disabled ? " disabled" : "");
  let html = `<span class="menu-check">${check ? "✓" : ""}</span>`;
  if (icon) html += `<span class="menu-icon">${icon}</span>`;
  html += `<span class="menu-label"></span>`;
  if (hint) html += `<span class="menu-hint">${hint}</span>`;
  if (badge) html += `<span class="menu-badge">↗</span>`;
  if (submenu) html += `<span class="menu-arrow">›</span>`;
  item.innerHTML = html;
  item.querySelector(".menu-label").textContent = label;
  if (submenu) item.appendChild(submenu);
  if (action) {
    item.addEventListener("click", (ev) => {
      ev.stopPropagation();
      action();
    });
  }
  return item;
}

function menuSeparator() {
  const sep = document.createElement("div");
  sep.className = "menu-sep";
  return sep;
}

function submenuOf(children) {
  const sub = document.createElement("div");
  sub.className = "menu submenu";
  children.forEach((c) => sub.appendChild(c));
  return sub;
}

function renderMenu() {
  menuEl.innerHTML = "";

  const sizeSub = submenuOf(Object.keys(SIZE_SCALES).map((size) =>
    menuItem({
      label: size,
      check: menuState.size === size,
      action() {
        menuState.size = size;
        setScale(SIZE_SCALES[size]);
        closeMenu();
      },
    })
  ));
  menuEl.appendChild(menuItem({ label: "Size", submenu: sizeSub }));

  const themeSub = submenuOf(S.themes.map((t) =>
    menuItem({
      label: t.title,
      check: theme.id === t.id,
      action() {
        userPickedTheme = true;
        setSpriteTheme(t);
        closeMenu();
      },
    })
  ));
  menuEl.appendChild(menuItem({ label: "Theme", submenu: themeSub }));

  // Opacity: slider row, dim icon → slider → solid icon, like the app's.
  const opacityRow = document.createElement("div");
  opacityRow.className = "menu-slider";
  opacityRow.innerHTML =
    '<svg viewBox="0 0 16 16"><circle cx="8" cy="8" r="6" fill="none" ' +
    'stroke="currentColor" stroke-width="1.4" opacity="0.45"/></svg>' +
    '<input type="range" min="10" max="100" aria-label="Opacity">' +
    '<svg viewBox="0 0 16 16"><circle cx="8" cy="8" r="6.7" fill="currentColor"/></svg>';
  const slider = opacityRow.querySelector("input");
  slider.value = String(Math.round(menuState.opacity * 100));
  slider.addEventListener("input", () => {
    menuState.opacity = slider.value / 100;
    canvas.style.opacity = menuState.opacity;
  });
  opacityRow.addEventListener("click", (ev) => ev.stopPropagation());
  menuEl.appendChild(menuItem({ label: "Opacity", submenu: submenuOf([opacityRow]) }));

  menuEl.appendChild(menuItem({ label: "Reset Position", action: closeMenu }));

  menuEl.appendChild(menuSeparator());
  menuEl.appendChild(menuItem({
    label: "Vaults…", hint: "⌃⌥V",
    action() { closePanels(); openHopper(); },
  }));
  menuEl.appendChild(menuItem({
    label: "Capture…", hint: "⌃⌥Space",
    action() { closePanels(); openCapture(); },
  }));

  menuEl.appendChild(menuSeparator());
  menuEl.appendChild(menuItem({
    label: "Undo Last Delivery",
    action() {
      closeMenu();
      showNotice("Nothing to undo", "No notes were couriered today");
    },
  }));
  menuEl.appendChild(menuItem({
    label: "Undo Last Capture",
    action() {
      closeMenu();
      showNotice("Nothing to undo", "Demo captures aren't real writes");
    },
  }));
  menuEl.appendChild(menuItem({
    label: "Copy on Drop",
    check: menuState.copyOnDrop,
    action() { menuState.copyOnDrop = !menuState.copyOnDrop; closeMenu(); },
  }));
  menuEl.appendChild(menuItem({
    label: "Show in Full Screen",
    check: menuState.showInFullScreen,
    action() { menuState.showInFullScreen = !menuState.showInFullScreen; closeMenu(); },
  }));

  const pluginItems = [
    { name: "Bookmark", desc: "Save a URL as a markdown note" },
    { name: "Code Snippet", desc: "Capture code from the clipboard" },
  ];
  const pluginsSub = submenuOf([
    ...pluginItems.map((p) => {
      const enabled = menuState.plugins[p.name] !== false;
      const item = menuItem({
        label: p.name,
        check: enabled,
        action() {
          menuState.plugins[p.name] = !enabled;
          closeMenu();
        },
      });
      const desc = document.createElement("span");
      desc.className = "menu-desc";
      desc.textContent = p.desc;
      item.querySelector(".menu-label").appendChild(desc);
      if (!enabled) item.classList.add("plugin-off");
      return item;
    }),
    menuSeparator(),
    menuItem({
      label: "Open Plugins Folder",
      action: closeMenu,
    }),
  ]);
  menuEl.appendChild(menuItem({ label: "Plugins", submenu: pluginsSub }));

  menuEl.appendChild(menuSeparator());
  menuEl.appendChild(menuItem({
    label: `Chestnut ${S.version || "dev"}`,
    disabled: true,
  }));
  menuEl.appendChild(menuItem({
    label: "Check for Updates…", badge: true,
    action() {
      closeMenu();
      window.open("https://github.com/gapmiss/chestnut/releases", "_blank", "noopener");
    },
  }));
  menuEl.appendChild(menuItem({
    label: "Support Chestnut", icon: HEART_SVG, badge: true,
    action() {
      closeMenu();
      window.open("https://github.com/sponsors/gapmiss", "_blank", "noopener");
    },
  }));

  menuEl.appendChild(menuSeparator());
  menuEl.appendChild(menuItem({
    label: "Launch at Login",
    check: menuState.launchAtLogin,
    action() { menuState.launchAtLogin = !menuState.launchAtLogin; closeMenu(); },
  }));
  menuEl.appendChild(menuItem({
    label: "Quit Chestnut",
    action() {
      closeMenu();
      const t = performance.now() / 1000;
      pet.state = "sleep";
      pet.zs = [];
      pet.nextZ = t + 0.5;
      pet.napUntil = t + 5;
      showNotice("Chestnut refuses to quit", "It lives here, it's just napping",
        "Demo only, the real menu item does quit");
    },
  }));
}

// Stage-relative coordinates; flips upward when it would run past the stage
// bottom, like a real context menu at the screen edge.
function openMenuAt(x, y) {
  closePanels(); // also closes an already-open menu
  renderMenu();
  menuEl.hidden = false;
  const w = menuEl.offsetWidth;
  const h = menuEl.offsetHeight;
  const left = Math.max(0, Math.min(x, stageEl.clientWidth - w));
  menuEl.style.left = left + "px";
  menuEl.style.top = (y + h > stageEl.clientHeight ? y - h : y) + "px";
  // Submenus open rightward unless that would leave the viewport.
  const flip =
    menuEl.getBoundingClientRect().right + 150 > document.documentElement.clientWidth;
  menuEl.querySelectorAll(".submenu").forEach((s) => s.classList.toggle("flip", flip));
  syncChips();
}

function closeMenu() {
  menuEl.hidden = true;
  syncChips();
}

canvas.addEventListener("contextmenu", (ev) => {
  if (!spriteHit(ev)) return;
  ev.preventDefault();
  const rect = stageEl.getBoundingClientRect();
  openMenuAt(ev.clientX - rect.left, ev.clientY - rect.top);
});

chipMenu.addEventListener("click", () => {
  if (!menuEl.hidden) { closeMenu(); return; }
  openMenuAt(
    stageEl.clientWidth / 2 + 40,
    stageEl.clientHeight - BASELINE - S.gridHeight * SCALE - 10
  );
});

document.addEventListener("pointerdown", (ev) => {
  if (menuEl.hidden) return;
  if (menuEl.contains(ev.target) || chipMenu.contains(ev.target)) return;
  closeMenu();
});

// ---------------------------------------------------------------------------
// Light/dark mode toggle + pixel section icons.
// The icons are drawn the same way as Chestnut — tiny character matrices,
// one fillRect per pixel — and recolor with the site mode.
// ---------------------------------------------------------------------------

const modeToggle = document.getElementById("mode-toggle");
const SUN_SVG =
  '<svg viewBox="0 0 16 16" aria-hidden="true"><circle cx="8" cy="8" r="3.4"/>' +
  '<path d="M8 .8v2.2M8 13v2.2M.8 8h2.2M13 8h2.2M2.9 2.9l1.6 1.6M11.5 11.5l1.6 1.6' +
  'M13.1 2.9l-1.6 1.6M4.5 11.5l-1.6 1.6"/></svg>';
const MOON_SVG =
  '<svg viewBox="0 0 16 16" aria-hidden="true">' +
  '<path d="M13.3 9.6A5.8 5.8 0 1 1 6.4 2.7a4.6 4.6 0 0 0 6.9 6.9z"/></svg>';

// Roles: a accent, A accent-bright, t text, d secondary.
const PIXEL_ICONS = {
  pin: [
    "....aaaa....",
    "...aaaaaa...",
    "..aAAaaaaa..",
    "..aAaaaaaa..",
    "..aaaaaaaa..",
    "..aaaaaaaa..",
    "...aaaaaa...",
    "....aaaa....",
    ".....aa.....",
    "...dddddd...",
  ],
  envelope: [
    "............",
    ".tttttttttt.",
    ".ta......at.",
    ".t.a....a.t.",
    ".t..a..a..t.",
    ".t...aa...t.",
    ".t........t.",
    ".tttttttttt.",
    "............",
    "............",
  ],
  pencil: [
    ".........aa.",
    "........aAa.",
    ".......aAa..",
    "......aAa...",
    ".....aAa....",
    "....aaa.....",
    "...ttt......",
    "..tt........",
    ".t..........",
    ".dddddddd...",
  ],
  note: [
    "..tttttt....",
    "..t....tt...",
    "..t....ttt..",
    "..t......t..",
    "..t.aaaa.t..",
    "..t......t..",
    "..t.aaaa.t..",
    "..t......t..",
    "..t.aaa..t..",
    "..tttttttt..",
  ],
};

function renderPixelIcons() {
  const style = getComputedStyle(document.documentElement);
  const colors = {
    a: style.getPropertyValue("--accent").trim(),
    A: style.getPropertyValue("--accent-bright").trim(),
    t: style.getPropertyValue("--text").trim(),
    d: style.getPropertyValue("--text-secondary").trim(),
  };
  const d = window.devicePixelRatio || 1;
  document.querySelectorAll("canvas.px-icon").forEach((c) => {
    const rows = PIXEL_ICONS[c.dataset.icon];
    if (!rows) return;
    const scale = Number(c.dataset.scale) || 3;
    c.width = rows[0].length * scale * d;
    c.height = rows.length * scale * d;
    c.style.width = rows[0].length * scale + "px";
    c.style.height = rows.length * scale + "px";
    const g = c.getContext("2d");
    g.scale(d, d);
    rows.forEach((row, y) => {
      [...row].forEach((ch, x) => {
        const color = colors[ch];
        if (!color) return;
        g.fillStyle = color;
        g.fillRect(x * scale, y * scale, scale, scale);
      });
    });
  });
}

function applyMode() {
  const mode = effectiveMode();
  modeToggle.innerHTML = mode === "dark" ? SUN_SVG : MOON_SVG;
  modeToggle.setAttribute(
    "aria-label",
    mode === "dark" ? "Switch to light mode" : "Switch to dark mode"
  );
  if (!userPickedTheme) setSpriteTheme(defaultThemeFor(mode));
  renderPixelIcons();
}

modeToggle.addEventListener("click", () => {
  const next = effectiveMode() === "dark" ? "light" : "dark";
  document.documentElement.dataset.theme = next;
  try { localStorage.setItem("chestnut-mode", next); } catch (e) { /* private mode */ }
  applyMode();
});

// Follow live OS scheme changes unless the toggle has set an override.
mediaLight.addEventListener("change", () => {
  if (!document.documentElement.dataset.theme) applyMode();
});

applyMode();
